func solve(n: Int) -> [String] {
  var out:[String]=[]
  for i in 1...n {
    var s=""
    if i%3==0 { s += "Fizz" }
    if i%5==0 { s += "Buzz" }
    out.append(s.isEmpty ? String(i) : s)
  }
  return out
}

