// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
func solve(_ rut: String) -> Bool {
  let clean = rut.replacingOccurrences(of: ".", with: "")
    .replacingOccurrences(of: "-", with: "")
    .replacingOccurrences(of: " ", with: "")
    .uppercased()

  if clean.count < 2 { return false }

  let body = String(clean.dropLast())
  let dv = clean.last!

  if body.contains(where: { !$0.isNumber }) { return false }

  var sum = 0
  var mul = 2
  for ch in body.reversed() {
    let d = Int(String(ch))!
    sum += d * mul
    mul = (mul == 7) ? 2 : (mul + 1)
  }

  let mod = 11 - (sum % 11)
  let dvCalc: Character = (mod == 11) ? "0" : (mod == 10) ? "K" : Character(String(mod))
  return dv == dvCalc
}

