// C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
import Foundation

func solve() throws {
  let inUrl = URL(fileURLWithPath: "input.csv")
  let outUrl = URL(fileURLWithPath: "output.csv")
  let content = try String(contentsOf: inUrl, encoding: .utf8)
  var lines = content.split(whereSeparator: \.isNewline).map(String.init)
  guard !lines.isEmpty else { return }

  let headers = lines[0].split(separator: ",").map(String.init)
  let emailIdx = headers.firstIndex(of: "Email")

  var outLines: [String] = []
  outLines.append(lines[0])

  for i in 1..<lines.count {
    var cols = lines[i].split(separator: ",", omittingEmptySubsequences: false).map(String.init)
    if let ei = emailIdx, ei < cols.count {
      cols[ei] = cols[ei].trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }
    outLines.append(cols.joined(separator: ","))
  }

  try outLines.joined(separator: "\n").write(to: outUrl, atomically: true, encoding: .utf8)
}

