// C0651 · Consumir API HTTP (GET y POST JSON) (Intermedio, HTTP)
import Foundation

func solve() async throws -> (Any, Any) {
  // GET
  let getUrl = URL(string: "https://httpbin.org/get")!
  let (getData, _) = try await URLSession.shared.data(from: getUrl)
  let getJson = try JSONSerialization.jsonObject(with: getData)

  // POST JSON
  let postUrl = URL(string: "https://httpbin.org/post")!
  var req = URLRequest(url: postUrl)
  req.httpMethod = "POST"
  req.setValue("application/json", forHTTPHeaderField: "Content-Type")
  req.httpBody = try JSONSerialization.data(withJSONObject: ["hello": "world"])

  let (postData, _) = try await URLSession.shared.data(for: req)
  let postJson = try JSONSerialization.jsonObject(with: postData)

  return (getJson, postJson)
}

