// C0661 · Retry + backoff + timeout (Intermedio, Resiliencia)
import Foundation

func solve(maxRetries: Int = 5) throws {
  var attempt = 0
  var delay: UInt64 = 200_000_000 // 200ms in ns
  while true {
    attempt += 1
    if Double.random(in: 0...1) >= 0.7 { return } // ok
    if attempt >= maxRetries { throw NSError(domain: "Retry", code: 1) }
    try await Task.sleep(nanoseconds: delay)
    delay = min(delay * 2, 5_000_000_000) // cap 5s
  }
}

