// C0665 · Binary search (iterativo) (Básico, Algoritmos)
func solve(_ arr: [Int], _ target: Int) -> Int {
  var lo = 0
  var hi = arr.count - 1
  while lo <= hi {
    let mid = lo + (hi - lo) / 2
    let v = arr[mid]
    if v == target { return mid }
    if v < target { lo = mid + 1 }
    else { hi = mid - 1 }
  }
  return -1
}

