// C0666 · Merge sort (Intermedio, Algoritmos)
func solve(_ arr: [Int]) -> [Int] {
  if arr.count <= 1 { return arr }
  let mid = arr.count / 2
  let left = solve(Array(arr[0..<mid]))
  let right = solve(Array(arr[mid..<arr.count]))
  var out: [Int] = []
  out.reserveCapacity(arr.count)
  var i = 0, j = 0
  while i < left.count && j < right.count {
    if left[i] <= right[j] { out.append(left[i]); i += 1 }
    else { out.append(right[j]); j += 1 }
  }
  if i < left.count { out.append(contentsOf: left[i...]) }
  if j < right.count { out.append(contentsOf: right[j...]) }
  return out
}

