// C0667 · BFS/DFS (grafo) (Intermedio, Algoritmos)
import Foundation

// g: adjacency list, vertices 0..n-1
func bfs(_ g: [[Int]], _ start: Int) -> [Int] {
  var q: [Int] = [start]
  var head = 0
  var seen = Array(repeating: false, count: g.count)
  var out: [Int] = []
  seen[start] = true

  while head < q.count {
    let v = q[head]; head += 1
    out.append(v)
    for nb in g[v] where !seen[nb] {
      seen[nb] = true
      q.append(nb)
    }
  }
  return out
}

func dfs(_ g: [[Int]], _ start: Int) -> [Int] {
  var seen = Array(repeating: false, count: g.count)
  var out: [Int] = []
  func visit(_ v: Int) {
    seen[v] = true
    out.append(v)
    for nb in g[v] where !seen[nb] { visit(nb) }
  }
  visit(start)
  return out
}

