// C0668 · A* (pathfinding) (Avanzado, Algoritmos)
import Foundation

func solve(_ grid: [[Int]], _ start: (Int,Int), _ goal: (Int,Int)) -> [(Int,Int)] {
  let h = grid.count
  let w = grid[0].count
  func hcost(_ a:(Int,Int), _ b:(Int,Int)) -> Int { abs(a.0-b.0) + abs(a.1-b.1) }
  func key(_ p:(Int,Int)) -> String { "\(p.0),\(p.1)" }

  func neighbors(_ p:(Int,Int)) -> [(Int,Int)] {
    let (x,y) = p
    let dirs = [(1,0),(-1,0),(0,1),(0,-1)]
    var out:[(Int,Int)] = []
    for (dx,dy) in dirs {
      let nx=x+dx, ny=y+dy
      if nx>=0 && ny>=0 && nx<w && ny<h && grid[ny][nx]==0 { out.append((nx,ny)) }
    }
    return out
  }

  var open:[(Int,(Int,Int))] = [(hcost(start,goal), start)]
  var came:[String:(Int,Int)] = [:]
  var g:[String:Int] = [key(start):0]

  while !open.isEmpty {
    open.sort { $0.0 < $1.0 }
    let cur = open.removeFirst().1
    if cur.0 == goal.0 && cur.1 == goal.1 {
      var path:[(Int,Int)] = [cur]
      var ck = key(cur)
      var c = cur
      while let prev = came[ck] {
        c = prev; path.append(c); ck = key(c)
      }
      return path.reversed()
    }
    for nb in neighbors(cur) {
      let nk = key(nb)
      let ng = (g[key(cur)] ?? Int.max) + 1
      if g[nk] == nil || ng < g[nk]! {
        g[nk] = ng
        came[nk] = cur
        open.append((ng + hcost(nb,goal), nb))
      }
    }
  }
  return []
}

