// C0669 · LRU cache (Intermedio, Algoritmos)
final class LRU<K: Hashable, V> {
  private let cap: Int
  private var dict: [K: V] = [:]
  private var order: [K] = [] // oldest..newest (simple, O(n) touch)

  init(_ cap: Int) { self.cap = cap }

  func get(_ k: K) -> V? {
    guard let v = dict[k] else { return nil }
    touch(k)
    return v
  }

  func put(_ k: K, _ v: V) {
    dict[k] = v
    touch(k)
    if order.count > cap {
      let oldest = order.removeFirst()
      dict.removeValue(forKey: oldest)
    }
  }

  private func touch(_ k: K) {
    if let i = order.firstIndex(of: k) { order.remove(at: i) }
    order.append(k)
  }
}

